const data = $input.first().json;
const level = data.level || 'Observateur';
const score = parseInt(data.score) || 0;

const content = {
  Observateur: {
    color: '#ea580c',
    bgColor: '#fff4ef',
    desc: "L'IA est encore en dehors de vos pratiques quotidiennes. C'est le bon moment pour poser les bases et identifier vos premiers cas d'usage concrets.",
    recos: [
      "Identifiez 2 ou 3 tâches répétitives que l'IA pourrait prendre en charge dans votre équipe",
      "Désignez un référent IA chargé de centraliser les expérimentations et partager les découvertes",
      "Testez un outil IA sur une tâche concrète cette semaine et documentez le résultat"
    ]
  },
  Explorateur: {
    color: '#b45309',
    bgColor: '#fffbeb',
    desc: "Votre équipe a commencé à explorer l'IA, mais les usages restent isolés. Il est temps de structurer et de systématiser.",
    recos: [
      "Créez un espace partagé pour centraliser les prompts et bonnes pratiques de l'équipe",
      "Automatisez un premier processus récurrent avec Make ou n8n",
      "Organisez une session de formation collective sur le prompt engineering"
    ]
  },
  Praticien: {
    color: '#0088cc',
    bgColor: '#eff8ff',
    desc: "L'IA fait partie de votre quotidien. Vous êtes en bonne position pour industrialiser vos pratiques et poser un cadre clair avant de scaler.",
    recos: [
      "Mettez en place une charte d'usage de l'IA pour encadrer les pratiques et la confidentialité",
      "Mesurez le retour sur investissement de vos automatisations actuelles pour les consolider",
      "Étendez les bonnes pratiques aux membres les moins avancés de l'équipe"
    ]
  },
  Pionnier: {
    color: '#16a34a',
    bgColor: '#f0fdf4',
    desc: "Votre équipe est en avance sur l'adoption de l'IA. L'enjeu est maintenant de scaler et de faire de cette maturité un avantage concurrentiel visible.",
    recos: [
      "Faites de votre maturité IA un argument visible auprès de vos clients et partenaires",
      "Explorez les modèles IA spécialisés à votre secteur pour aller encore plus loin",
      "Diffusez la culture IA à toute l'organisation, au-delà de votre équipe directe"
    ]
  }
};

const lc = content[level] || content['Observateur'];

const questionLabels = {
  q1: "Outils IA utilisés dans l'équipe",
  q2: "Automatisations IA en place",
  q3: "Gains de temps liés à l'IA",
  q4: "Niveau de maîtrise IA",
  q5: "Formation aux outils IA",
  q6: "Documentation des bonnes pratiques",
  q7: "Organisation des données",
  q8: "Standardisation des processus",
  q9: "IA dans les prises de décision",
  q10: "Vision stratégique de la direction",
  q11: "Culture de partage sur l'IA",
  q12: "Gouvernance et règles IA"
};

const answerMap = { 1: '1/4', 2: '2/4', 3: '3/4', 4: '4/4' };
const answers = data.answers || {};

let qaRows = '';
for (const [key, val] of Object.entries(answers)) {
  const label = questionLabels[key] || key;
  const valueLabel = answerMap[val] || val;
  qaRows += '<tr>' +
    '<td style="padding:8px 12px;font-size:13px;color:#555;border-bottom:1px solid #f0f0f0;">' + label + '</td>' +
    '<td style="padding:8px 12px;font-size:13px;font-weight:600;color:#111;border-bottom:1px solid #f0f0f0;white-space:nowrap;">' + valueLabel + '</td>' +
    '</tr>';
}

const recoItems = lc.recos
  .map(r => '<li style="font-size:14px;color:#444;margin-bottom:8px;line-height:1.55;">' + r + '</li>')
  .join('');

return [{
  json: {
    email: data.email || '',
    phone: data.phone || null,
    score,
    level,
    levelColor: lc.color,
    levelBgColor: lc.bgColor,
    levelDesc: lc.desc,
    recoItems,
    qaRows,
    phoneDisplay: data.phone || 'Non renseigné'
  }
}];
